package format

import (
	"bytes"
	"fmt"
	"sort"

	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/terraform"
)

// CompactDiffFormatter produces a condensed, summary-style diff output for a
// Terraform plan. Each resource change is rendered as a single line grouped
// under its action type, followed by a summary count line.
type CompactDiffFormatter struct{}

// actionGroup associates a plans.Action with its human-readable heading and
// the plain-text symbol shown before each resource address.
type actionGroup struct {
	action  plans.Action
	heading string
	symbol  string
}

// orderedActionGroups defines the display order and labelling for every action
// type that CompactDiffFormatter renders. NoOp resources are never listed (they
// represent unchanged resources); moved-only NoOp resources are handled
// separately as the "move" pseudo-group.
var orderedActionGroups = []actionGroup{
	{plans.Create, "create", "+"},
	{plans.Update, "update in-place", "~"},
	{plans.Delete, "destroy", "-"},
	{plans.DeleteThenCreate, "replace (destroy then create)", "-/+"},
	{plans.CreateThenDelete, "replace (create then destroy)", "+/-"},
	{plans.Forget, "remove from state", "~"},
	{plans.CreateThenForget, "create and remove from state", "+"},
	{plans.Read, "read", "<="},
}

// Format renders plan as a compact diff string. The schemas argument is
// accepted for API consistency with other formatters but is not required for
// resource-level summary output.
func (f *CompactDiffFormatter) Format(plan *plans.Plan, _ *terraform.Schemas) string {
	if plan == nil || plan.Changes == nil || len(plan.Changes.Resources) == 0 {
		return "No changes. Your infrastructure matches the configuration.\n"
	}

	// Collect resource addresses by action and track moved resources.
	byAction := make(map[plans.Action][]string)
	var movedAddrs []string

	for _, rc := range plan.Changes.Resources {
		if rc.Action == plans.NoOp {
			if rc.Moved() {
				movedAddrs = append(movedAddrs, fmt.Sprintf("%s => %s", rc.PrevRunAddr.String(), rc.Addr.String()))
			}
			continue
		}
		byAction[rc.Action] = append(byAction[rc.Action], rc.Addr.String())
	}

	// Sort addresses within each group for deterministic output.
	for action := range byAction {
		sort.Strings(byAction[action])
	}
	sort.Strings(movedAddrs)

	hasChanges := len(movedAddrs) > 0
	for _, g := range orderedActionGroups {
		if len(byAction[g.action]) > 0 {
			hasChanges = true
			break
		}
	}

	if !hasChanges {
		return "No changes. Your infrastructure matches the configuration.\n"
	}

	var buf bytes.Buffer
	buf.WriteString("Terraform will perform the following actions:\n")

	// Render moved resources first.
	if len(movedAddrs) > 0 {
		buf.WriteString("\n  # move\n")
		for _, addr := range movedAddrs {
			fmt.Fprintf(&buf, "  > %s\n", addr)
		}
	}

	// Render each action group in the defined order.
	for _, g := range orderedActionGroups {
		addrs, ok := byAction[g.action]
		if !ok {
			continue
		}
		fmt.Fprintf(&buf, "\n  # %s\n", g.heading)
		for _, addr := range addrs {
			fmt.Fprintf(&buf, "  %s %s\n", g.symbol, addr)
		}
	}

	buf.WriteByte('\n')
	buf.WriteString(f.summary(plan.Changes.Resources))
	buf.WriteByte('\n')

	return buf.String()
}

// summary produces the "Plan: N to add, N to change, N to destroy." line.
func (f *CompactDiffFormatter) summary(resources []*plans.ResourceInstanceChangeSrc) string {
	var toAdd, toChange, toDestroy, toForget int

	for _, rc := range resources {
		switch rc.Action {
		case plans.Create:
			toAdd++
		case plans.Update:
			toChange++
		case plans.Delete:
			toDestroy++
		case plans.DeleteThenCreate, plans.CreateThenDelete:
			toAdd++
			toDestroy++
		case plans.Forget:
			toForget++
		case plans.CreateThenForget:
			toAdd++
			toForget++
		}
	}

	if toAdd == 0 && toChange == 0 && toDestroy == 0 && toForget == 0 {
		return "Plan: 0 changes."
	}

	var parts []string
	if toAdd > 0 {
		parts = append(parts, fmt.Sprintf("%d to add", toAdd))
	}
	if toChange > 0 {
		parts = append(parts, fmt.Sprintf("%d to change", toChange))
	}
	if toDestroy > 0 {
		parts = append(parts, fmt.Sprintf("%d to destroy", toDestroy))
	}
	if toForget > 0 {
		parts = append(parts, fmt.Sprintf("%d to remove from state", toForget))
	}

	summary := "Plan:"
	for i, p := range parts {
		if i == 0 {
			summary += " " + p
		} else {
			summary += ", " + p
		}
	}
	summary += "."
	return summary
}

