// Copyright (c) HashiCorp, Inc.
// SPDX-License-Identifier: BUSL-1.1

package format

import (
	"testing"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/states"
)

// absResourceInstance is a helper that builds an addrs.AbsResourceInstance for
// a managed resource in the root module without an instance key.
func absResourceInstance(resourceType, name string) addrs.AbsResourceInstance {
	return addrs.RootModuleInstance.ResourceInstance(
		addrs.ManagedResourceMode,
		resourceType,
		name,
		addrs.NoKey,
	)
}

// changesSrc builds a *plans.ChangesSrc containing one ResourceInstanceChangeSrc
// per provided spec. Each spec is a [3]string{resourceType, name, ""} accompanied
// by an Action; the PrevRunAddr equals Addr (no move).
func makeChanges(specs []resourceChangeSpec) *plans.ChangesSrc {
	cs := plans.NewChangesSrc()
	for _, s := range specs {
		addr := absResourceInstance(s.resourceType, s.name)
		prevAddr := addr
		if s.prevName != "" {
			prevAddr = absResourceInstance(s.prevResourceType, s.prevName)
		}
		cs.Resources = append(cs.Resources, &plans.ResourceInstanceChangeSrc{
			Addr:        addr,
			PrevRunAddr: prevAddr,
			DeposedKey:  states.NotDeposed,
			ChangeSrc: plans.ChangeSrc{
				Action: s.action,
			},
		})
	}
	return cs
}

type resourceChangeSpec struct {
	resourceType     string
	name             string
	action           plans.Action
	prevResourceType string // non-empty only for moves
	prevName         string // non-empty only for moves
}

func TestCompactDiffFormatter_Format(t *testing.T) {
	f := &CompactDiffFormatter{}

	tests := []struct {
		name        string
		plan        *plans.Plan
		wantContain []string // substrings that must appear in output
		wantAbsent  []string // substrings that must NOT appear in output
	}{
		{
			name:        "nil plan",
			plan:        nil,
			wantContain: []string{"No changes."},
		},
		{
			name:        "nil Changes",
			plan:        &plans.Plan{Changes: nil},
			wantContain: []string{"No changes."},
		},
		{
			name: "empty Changes",
			plan: &plans.Plan{Changes: plans.NewChangesSrc()},
			wantContain: []string{"No changes."},
		},
		{
			name: "all NoOp resources produce no changes output",
			plan: &plans.Plan{Changes: makeChanges([]resourceChangeSpec{
				{resourceType: "aws_instance", name: "web", action: plans.NoOp},
				{resourceType: "aws_s3_bucket", name: "data", action: plans.NoOp},
			})},
			wantContain: []string{"No changes."},
		},
		{
			name: "single create",
			plan: &plans.Plan{Changes: makeChanges([]resourceChangeSpec{
				{resourceType: "aws_instance", name: "web", action: plans.Create},
			})},
			wantContain: []string{
				"Terraform will perform the following actions:",
				"# create",
				"+ aws_instance.web",
				"Plan: 1 to add.",
			},
			wantAbsent: []string{"No changes."},
		},
		{
			name: "single update",
			plan: &plans.Plan{Changes: makeChanges([]resourceChangeSpec{
				{resourceType: "aws_security_group", name: "rules", action: plans.Update},
			})},
			wantContain: []string{
				"# update in-place",
				"~ aws_security_group.rules",
				"Plan: 1 to change.",
			},
		},
		{
			name: "single delete",
			plan: &plans.Plan{Changes: makeChanges([]resourceChangeSpec{
				{resourceType: "aws_instance", name: "old", action: plans.Delete},
			})},
			wantContain: []string{
				"# destroy",
				"- aws_instance.old",
				"Plan: 1 to destroy.",
			},
		},
		{
			name: "replace destroy-then-create",
			plan: &plans.Plan{Changes: makeChanges([]resourceChangeSpec{
				{resourceType: "aws_instance", name: "server", action: plans.DeleteThenCreate},
			})},
			wantContain: []string{
				"# replace (destroy then create)",
				"-/+ aws_instance.server",
				"Plan: 1 to add, 1 to destroy.",
			},
		},
		{
			name: "replace create-then-destroy",
			plan: &plans.Plan{Changes: makeChanges([]resourceChangeSpec{
				{resourceType: "aws_instance", name: "server", action: plans.CreateThenDelete},
			})},
			wantContain: []string{
				"# replace (create then destroy)",
				"+/- aws_instance.server",
				"Plan: 1 to add, 1 to destroy.",
			},
		},
		{
			name: "forget (remove from state)",
			plan: &plans.Plan{Changes: makeChanges([]resourceChangeSpec{
				{resourceType: "aws_instance", name: "imported", action: plans.Forget},
			})},
			wantContain: []string{
				"# remove from state",
				"~ aws_instance.imported",
				"Plan: 1 to remove from state.",
			},
		},
		{
			name: "create-then-forget",
			plan: &plans.Plan{Changes: makeChanges([]resourceChangeSpec{
				{resourceType: "aws_instance", name: "ephemeral", action: plans.CreateThenForget},
			})},
			wantContain: []string{
				"# create and remove from state",
				"+ aws_instance.ephemeral",
				"Plan: 1 to add, 1 to remove from state.",
			},
		},
		{
			name: "read (data source)",
			plan: &plans.Plan{Changes: makeChanges([]resourceChangeSpec{
				{resourceType: "aws_ami", name: "latest", action: plans.Read},
			})},
			wantContain: []string{
				"# read",
				"<= aws_ami.latest",
			},
			// Read resources do not contribute to add/change/destroy counts.
			wantAbsent: []string{"Plan: 0 changes."},
		},
		{
			name: "mixed actions grouped correctly",
