		name,
		addrs.NoKey,
	)
}

// changesSrc builds a *plans.ChangesSrc containing one ResourceInstanceChangeSrc
// per provided spec. Each spec is a [3]string{resourceType, name, ""} accompanied
// by an Action; the PrevRunAddr equals Addr (no move).
func makeChanges(specs []resourceChangeSpec) *plans.ChangesSrc {
	cs := plans.NewChangesSrc()
	for _, s := range specs {
		addr := absResourceInstance(s.resourceType, s.name)
		prevAddr := addr
		if s.prevName != "" {
			prevAddr = absResourceInstance(s.prevResourceType, s.prevName)
		}
		cs.Resources = append(cs.Resources, &plans.ResourceInstanceChangeSrc{
			Addr:        addr,
			PrevRunAddr: prevAddr,
			DeposedKey:  states.NotDeposed,
			ChangeSrc: plans.ChangeSrc{
